StructuredTextModel.Text:
IF (Enable) THEN
	Enable_R(CLK := Enable);
	Punch_Zone(Enable := TRUE, Pos := C_Pos, Angle1 := 179, Angle2 := 181);
	In_Zone_R(CLK := Punch_Zone.In_Zone);
	
	// Do not count first stroke since it isn't a complete stroke, only half of one
	First_Stroke_Flag := Enable_R.Q;
	
	// Time in-between each punch
	Punch_Timer(In := (NOT In_Zone_R.Q), PT := T#100s);
	
	// Add our times together to get an accurate reading
	IF (In_Zone_R.Q AND (NOT First_Stroke_Flag)) THEN
		Punch_Time[I] := (LINT_TO_REAL(TimeToNanoSec(Punch_Timer.ET)));
		Punch_Time[I] := Punch_Time[I]*REAL#10.0**-9;
		
		// Increase the index for each new value saved
		I := I +1;
		IF (I >= UINT_TO_INT(SizeOfAry(Punch_Time))) THEN
			I := 0;
		END_IF;
	ELSIF (First_Stroke_Flag) THEN
		// Remove the flag after first time going through 180 degrees
		First_Stroke_Flag := FALSE;
	END_IF;

	// Use an average of the times
	I_Lim_R(CLK := (I = 0));
	IF (I_Lim_R.Q) THEN
		SPM := 0;
		FOR J := 0 TO (UINT_TO_INT(SizeOfAry(Punch_Time))-1) DO
			SPM := SPM + Punch_Time[J];
			Punch_Time[J] := 0;
		END_FOR;
		// SPM in seconds per punch
		SPM := SPM/(SizeOfAry(Punch_Time));
		// Convert to punches per minute
		SPM := SPM/60;
	END_IF;
ELSE
	// Initialize all values when the press is not running
	SPM := 0;
	I := 0;
	Zone_Trigger := FALSE;
	Punch_Time := Punch_Time_Init;
END_IF;
